// An unreliable 3rd-party library
function trackAnalytics(data, callback) {
  // simulate network delay
  setTimeout(() => {
    callback();
    // BUG: The library author accidentally called it twice!
    callback(); 
  }, 500);
}

// Your application code
let chargeCount = 0;
function chargeCreditCard() {
  chargeCount++;
  console.log(`Card charged! Total charges: ${chargeCount}`);
}

// You inverted control to trackAnalytics
trackAnalytics('Purchase Event', () => {
  chargeCreditCard(); //  User gets charged TWICE!
});

