let cache = null;
function getData(callback) {
  if (cache) {
    callback(cache); //  Synchronous! (Releasing Zalgo)
  } else {
    setTimeout(() => { cache = 'Data'; callback(cache); }, 100); // Async!
  }
}

let flag = false;
getData(() => console.log('Flag is:', flag));
flag = true;
// If cached, output is false. If not cached, output is true. Unpredictable!
